// --- Secure Dynamic Query Builder ---

class SecureQueryBuilder {
  private conditions: string[] = [];
  private values: any[] = [];
  private paramIndex = 1;

  /**
   * Add an exact match condition using parameterized query.
   * NEVER interpolates user input directly into SQL.
   */
  addExactMatch(column: string, value: any): this {
    if (value === undefined || value === null) return this;
    this.validateColumnName(column);
    this.conditions.push(`${column} = $${this.paramIndex}`);
    this.values.push(value);
    this.paramIndex++;
    return this;
  }

  /**
   * Add a partial text search using ILIKE with parameterized value.
   * The % wildcards are added to the parameter value, NOT to the SQL string.
   */
  addPartialMatch(column: string, value: string | undefined): this {
    if (value === undefined || value === null || value.trim() === "") return this;
    this.validateColumnName(column);
    this.conditions.push(`${column} ILIKE $${this.paramIndex}`);
    this.values.push(`%${value}%`);
    this.paramIndex++;
    return this;
  }

  /**
   * Add a range condition (greater than, less than, etc.)
   */
  addComparison(
    column: string,
    operator: ">=" | "<=" | ">" | "<",
    value: any
  ): this {
    if (value === undefined || value === null) return this;
    this.validateColumnName(column);
    if (!ALLOWED_FILTER_OPERATORS.has(operator)) {
      throw new Error(`Invalid operator: ${operator}`);
    }
    this.conditions.push(`${column} ${operator} $${this.paramIndex}`);
    this.values.push(value);
    this.paramIndex++;
    return this;
  }

  /**
   * Add an IN clause with parameterized values.
   */
  addInClause(column: string, values: any[] | undefined): this {
    if (!values || values.length === 0) return this;
    this.validateColumnName(column);
    const placeholders = values.map((_, i) => `$${this.paramIndex + i}`).join(", ");
    this.conditions.push(`${column} IN (${placeholders})`);
    this.values.push(...values);
    this.paramIndex += values.length;
    return this;
  }

  /**
   * Add a date range condition.
   */
  addDateRange(column: string, after?: string, before?: string): this {
    if (after) {
      this.addComparison(column, ">=", after);
    }
    if (before) {
      this.addComparison(column, "<=", before);
    }
    return this;
  }

  /**
   * Validate column name against whitelist to prevent SQL injection
   * through column name manipulation.
   */
  private validateColumnName(column: string): void {
    // Only allow alphanumeric characters, underscores, and dots (for table.column)
    const validColumnRegex = /^[a-zA-Z_][a-zA-Z0-9_.]*$/;
    if (!validColumnRegex.test(column)) {
      throw new Error(`Invalid column name: ${column}`);
    }
  }

  getWhereClause(): string {
    if (this.conditions.length === 0) return "";
    return `WHERE ${this.conditions.join(" AND ")}`;
  }

  getValues(): any[] {
    return this.values;
  }

  getParamIndex(): number {
    return this.paramIndex;
  }
}

